<?php
if (!function_exists('prod_t')) {
  function prod_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('prod_h')) {
  function prod_h($key, $fallback = '') { return htmlspecialchars((string) prod_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('prod_js')) {
  function prod_js($key, $fallback = '') { return json_encode(prod_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-01');$defaultTo=date('Y-m-d');
$plants=$db->query("SELECT DISTINCT plant_code FROM erp_production_downtime WHERE plant_code IS NOT NULL AND plant_code<>'' UNION SELECT DISTINCT plant FROM production_order WHERE plant IS NOT NULL AND plant<>'' ORDER BY plant_code");
$shifts=$db->query("SELECT id,kode_shift,nama_shift,jam_mulai,jam_selesai FROM erp_shift WHERE status='Aktif' ORDER BY kode_shift");
$kpi=$db->fetch("SELECT COUNT(*) total_doc,COALESCE(SUM(duration_minutes),0) total_minutes,SUM(impact_type='UNPLANNED') unplanned_doc,SUM(approval_status='CANCELLED') cancelled_doc FROM erp_production_downtime WHERE downtime_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
