Y</option><option>SETUP</option><option>OTHER</option></select></div><label class="control-label col-lg-1"><?=prod_h('common_search', 'Search');?></label><div class="col-lg-2"><input id="filter_keyword" class="form-control" placeholder="Downtime, PO, reason"></div><div class="col-lg-2"><button id="btn_filter_idt" class="btn btn-primary"><i class="fa fa-filter"></i></button> <button id="btn_reset_idt" class="btn btn-default"><i class="fa fa-refresh"></i></button> <button id="btn_excel_idt" class="btn btn-success"><i class="fa fa-file-excel-o"></i></button></div></div></form></div></div>
