  <div id="modal_idt" class="modal fade"><div class="modal-dialog modal-lg" style="width:92%"><form id="form_idt" class="modal-content idt-form"><div class="modal-header"><button class="close" data-dismiss="modal">&times;</button><h4 class="modal-title">Record Downtime</h4></div><div class="modal-body"><div class="row"><div class="col-md-6 form-group"><label><?=prod_h('production_order', 'Production Order');?></label><select name="production_id" id="production_id" class="form-control"></select><small class="text-muted">Opsional. Pilih jika downtime terkait order tertentu.</small></div><div class="col-md-6 form-group"><label><?=prod_h('production_operation', 'Operation');?></label><select name="operation_id" id="operation_id" class="form-control"></select></div></div><div class="row"><div class="col-md-3 form-group"><label class="required-label"><?=prod_h('production_work_center', 'Work Center');?></label><select name="work_center" id="work_center" class="form-control" required></select><input type="hidden" name="work_center_name" id="work_center_name"></div><div class="col-md-2 form-group"><label><?=prod_h('production_plant', 'Plant');?></label><input name="plant_code" id="plant_code" class="form-control"></div><div class="col-md-3 form-group"><label><?=prod_h('production_shift', 'Shift');?></label><select name="shift_id" id="shift_id" class="form-control"><option value="">-</option><?php foreach($shifts as $s){ ?><option value="<?=intval($s->id);?>"><?=htmlspecialchars($s->kode_shift.' - '.$s->nama_shift.' ('.$s->jam_mulai.'-'.$s->jam_selesai.')',ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><div class="col-md-2 form-group"><label>Impact</label><select name="impact_type" class="form-control"><option>UNPLANNED</option><option>PLANNED</option></select></div><div class="col-md-2 form-group"><label>Duration</label><input id="duration_preview" class="form-control text-right" readonly value="0 min"></div></div><div class="row"><div class="col-md-3 form-group"><label class="required-label">Start Time</label><input type="datetime-local" name="start_time" id="start_time" class="form-control" value="<?=date('Y-m-d');?>T08:00" required></div><div class="col-md-3 form-group"><label class="required-label">End Time</label><input type="datetime-local" name="end_time" id="end_time" class="form-control" value="<?=date('Y-m-d');?>T08:30" required></div><div class="col-md-3 form-group"><label class="required-label">Category</label><select name="downtime_category" class="form-control" required><option>MACHINE</option><option>MATERIAL</option><option>MANPOWER</option><option>METHOD</option><option>QUALITY</option><option>UTILITY</option><option>SETUP</option><option>OTHER</option></select></div><div class="col-md-3 form-group"><label>Reason Code</label><input name="reason_code" class="form-control" placeholder="BD-MCH / NO-MAT"></div></div><div class="row"><div class="col-md-6 form-group"><label class="required-label">Reason Text</label><input name="reason_text" class="form-control" required placeholder="Contoh: Mesin coating stop karena sensor error"></div><div class="col-md-3 form-group"><label>Responsibility</label><input name="responsibility" class="form-control" placeholder="Maintenance / Production / Warehouse"></div><div class="col-md-3 form-group"><label><?=prod_h('common_remarks', 'Remarks');?></label><input name="remarks" class="form-control"></div></div><div class="form-group"><label>Action Taken</label><textarea name="action_taken" class="form-control" rows="2" placeholder="Tindakan perbaikan / countermeasure"></textarea></div></div><div class="modal-footer"><button type="button" class="btn btn-default" data-dismiss="modal"><?=prod_h('common_close', 'Close');?></button><button type="submit" class="btn btn-primary"><i class="fa fa-save"></i> Save Downtime</button></div></form></div></div>
