<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function idtError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_input_downtime_process_failed', 'Input Downtime failed to process.');?>);$('.error_data_delete').fadeIn();}
function idtFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),plant:$('#filter_plant').val(),work_center:$('#filter_work_center').val(),category:$('#filter_category').val(),status:$('#filter_status').val(),keyword:$('#filter_keyword').val()};}
function idtQuery(){return $.param(idtFilters());}
function calcDuration(){var s=new Date($('#start_time').val()),e=new Date($('#end_time').val());var m=(!isNaN(s)&&!isNaN(e)&&e>s)?Math.round((e-s)/60000):0;$('#duration_preview').val(m+' min');}
$(function(){if($.fn.datepicker){$('.idt-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant,#filter_category,#filter_status,#shift_id').select2({width:'100%',allowClear:true});$('#production_id').select2({width:'100%',allowClear:true,placeholder:<?=prod_js('production_search_production_order', 'Search Production Order...');?>,minimumInputLength:1,ajax:{url:'<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=order_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});$('#operation_id').select2({width:'100%',allowClear:true,placeholder:'Pilih operation...',ajax:{url:'<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=operations',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||'',production_id:$('#production_id').val()};},processResults:function(d){return{results:d.results||[]};}}});$('#work_center').select2({width:'100%',allowClear:true,placeholder:'Cari Work Center...',minimumInputLength:0,ajax:{url:'<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=work_center_search',type:'POST',dataType:'json',delay:250,data:function(p){return{term:p.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
var dt=$('#dtb_input_downtime').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'80px',targets:1}],ajax:{url:'<?=base_admin();?>modul/input_downtime/input_downtime_data.php',type:'post',data:function(d){$.extend(d,idtFilters());},error:function(xhr){console.log(xhr.responseText);idtError(<?=prod_js('production_downtime_load_failed', 'Downtime data failed to load.');?>);}}});
$('#btn_filter_idt').click(function(){dt.draw();});$('#filter_keyword,#filter_work_center').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_idt').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_plant,#filter_category,#filter_status').val('').trigger('change');$('#filter_work_center,#filter_keyword').val('');dt.draw();});$('#btn_excel_idt').click(function(){window.location='<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=excel&'+idtQuery();});
$('#btn_add_idt').click(function(){document.getElementById('form_idt').reset();$('#production_id,#operation_id,#work_center,#shift_id').val(null).trigger('change');$('#start_time').val('<?=date('Y-m-d');?>T08:00');$('#end_time').val('<?=date('Y-m-d');?>T08:30');calcDuration();$('#modal_idt').modal({backdrop:'static',keyboard:false});});
$('#start_time,#end_time').on('change keyup',calcDuration);$('#production_id').on('select2:select',function(e){var d=e.params.data;$('#plant_code').val(d.plant||'');$('#operation_id').val(null).trigger('change');});$('#operation_id').on('select2:select',function(e){var d=e.params.data;if(d.work_center){var opt=new Option(d.work_center,d.work_center,true,true);$('#work_center').append(opt).trigger('change');$('#work_center_name').val(d.work_center);}});$('#work_center').on('select2:select',function(e){$('#work_center_name').val(e.params.data.work_center_name||e.params.data.text||'');});
$('#form_idt').submit(function(e){e.preventDefault();$.post('<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=save',$(this).serialize(),function(r){if(r.status==='good'){$('#modal_idt').modal('hide');dt.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Downtime '+(r.downtime_no||'')+' tersimpan.','success');}else idtError(r.error_message);},'json').fail(function(xhr){console.log(xhr.responseText);idtError('Downtime gagal disimpan.');});});
$(document).on('click','.btn-idt-detail',function(){$.post('<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=detail',{id:$(this).data('id')},function(html){$('#idt_detail_body').html(html);$('#modal_detail_idt').modal('show');}).fail(function(){idtError('Detail gagal dibuka.');});});
$(document).on('click','.btn-idt-cancel',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:'Cancel Downtime?',text:no,input:'text',inputLabel:'Reason',showCancelButton:true,confirmButtonText:'Cancel'}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/input_downtime/input_downtime_action.php?act=cancel',{id:id,reason:x.value||''},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(<?=prod_js('common_success', 'Success');?>,'Downtime dibatalkan.','success');}else idtError(r.error_message);},'json').fail(function(){idtError(<?=prod_js('production_cancel_failed', 'Cancel failed.');?>);});});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
